package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  private static Class<?> recordClassMock;
  private static String[] expectedNames;

  @BeforeAll
  static void setUp() {
    recordClassMock = String.class; // Using String.class as a dummy class for testing
    expectedNames = new String[] {"name1", "name2"};
  }

  @Test
  void testGetRecordComponentNames_returnsExpected() {
    try (MockedStatic<RecordHelper> mockedRecordHelperStatic = Mockito.mockStatic(ReflectionHelper.class, Mockito.CALLS_REAL_METHODS)) {
      RecordHelper recordHelperMock = mock(RecordHelper.class);
      // Inject the mock into the private static field RECORD_HELPER using reflection
      setFinalStatic(ReflectionHelper.class.getDeclaredField("RECORD_HELPER"), recordHelperMock);

      when(recordHelperMock.getRecordComponentNames(recordClassMock)).thenReturn(expectedNames);

      String[] actual = ReflectionHelper.getRecordComponentNames(recordClassMock);
      assertArrayEquals(expectedNames, actual);

      verify(recordHelperMock).getRecordComponentNames(recordClassMock);
    } catch (NoSuchFieldException | IllegalAccessException e) {
      fail("Reflection error: " + e.getMessage());
    }
  }

  @Test
  void testGetRecordComponentNames_nullClass() {
    try {
      // Inject a dummy RecordHelper that returns null
      RecordHelper recordHelperMock = mock(RecordHelper.class);
      setFinalStatic(ReflectionHelper.class.getDeclaredField("RECORD_HELPER"), recordHelperMock);
      when(recordHelperMock.getRecordComponentNames(null)).thenReturn(null);

      String[] actual = ReflectionHelper.getRecordComponentNames(null);
      assertNull(actual);

      verify(recordHelperMock).getRecordComponentNames(null);
    } catch (NoSuchFieldException | IllegalAccessException e) {
      fail("Reflection error: " + e.getMessage());
    }
  }

  private static void setFinalStatic(Field field, Object newValue) throws NoSuchFieldException, IllegalAccessException {
    field.setAccessible(true);

    // Remove final modifier from field
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(field, field.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

    field.set(null, newValue);
  }

  // Dummy RecordHelper interface to enable mocking
  private interface RecordHelper {
    String[] getRecordComponentNames(Class<?> raw);
  }
}
